CREATE OR REPLACE FUNCTION public.add_order_to_table(p_table_session_id uuid, p_comanda_name text, p_items jsonb, p_notes text, p_waiter_id uuid)
 RETURNS bigint
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_restaurant_id uuid := get_my_restaurant_id();
    v_session record;
    v_comanda_id uuid;
    v_order_total numeric := 0;
    v_order_id bigint;
    item jsonb;
BEGIN
    -- Valida a sessão da mesa
    SELECT * INTO v_session FROM public.table_sessions
    WHERE id = p_table_session_id AND restaurant_id = v_restaurant_id AND closed_at IS NULL;

    IF v_session IS NULL THEN
        RAISE EXCEPTION 'Sessão da mesa não encontrada, inválida ou já fechada.';
    END IF;

    -- Procura pela comanda ou cria uma nova se não existir
    SELECT id INTO v_comanda_id FROM public.comandas
    WHERE table_session_id = p_table_session_id AND "name" = p_comanda_name;

    IF v_comanda_id IS NULL THEN
        INSERT INTO public.comandas (table_session_id, "name")
        VALUES (p_table_session_id, p_comanda_name)
        RETURNING id INTO v_comanda_id;
    END IF;

    -- Calcula o total do novo pedido
    FOR item IN SELECT * FROM jsonb_array_elements(p_items)
    LOOP
        v_order_total := v_order_total + ((item->>'quantity')::numeric * (item->>'unit_price')::numeric);
    END LOOP;

    -- Cria o pedido, agora incluindo o waiter_id
    INSERT INTO public.orders (restaurant_id, customer_id, source, status, total, notes, table_session_id, comanda_id, waiter_id)
    VALUES (v_restaurant_id, 1, 'mesa', 'preparacao', v_order_total, p_notes, p_table_session_id, v_comanda_id, p_waiter_id) -- customer_id=1 (placeholder)
    RETURNING id INTO v_order_id;

    -- Insere os itens do pedido
    INSERT INTO public.order_items (order_id, product_id, product_name, quantity, unit_price)
    SELECT v_order_id, (i->>'product_id')::bigint, i->>'product_name', (i->>'quantity')::numeric, (i->>'unit_price')::numeric
    FROM jsonb_array_elements(p_items) as i;

    -- Atualiza os totais na comanda e na sessão da mesa
    UPDATE public.comandas SET total_amount = total_amount + v_order_total WHERE id = v_comanda_id;
    UPDATE public.table_sessions SET total_amount = total_amount + v_order_total WHERE id = p_table_session_id;

    RETURN v_order_id;
END;
$function$

