    END LOOP;

    -- Cria o pedido, agora incluindo o waiter_id e waiter_name
    INSERT INTO public.orders (restaurant_id, customer_id, source, status, total, notes, table_session_id, comanda_id, waiter_id, waiter_name)
    VALUES (v_restaurant_id, 1, 'mesa', 'preparacao', v_order_total, p_notes, p_table_session_id, v_comanda_id, p_waiter_id, p_waiter_name)
    RETURNING id INTO v_order_id;

    -- Insere os itens do pedido
    INSERT INTO public.order_items (order_id, product_id, product_name, quantity, unit_price)
