    FROM jsonb_array_elements(p_items) as i;

    -- Atualiza os totais na comanda e na sessão da mesa
    UPDATE public.comandas SET total_amount = total_amount + v_order_total WHERE id = v_comanda_id;
    UPDATE public.table_sessions SET total_amount = total_amount + v_order_total WHERE id = p_table_session_id;

    RETURN v_order_id;
END;
$function$

CREATE OR REPLACE FUNCTION public.add_order_to_table(p_table_session_id bigint, p_comanda_name text, p_items jsonb, p_notes text, p_waiter_id uuid)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_order_id bigint;
    v_comanda_id bigint;
    v_total_price numeric := 0;
    item record;
    v_restaurant_id uuid;
BEGIN
    -- Calcula o preço total do pedido
    FOR item IN SELECT * FROM jsonb_to_recordset(p_items) AS x(product_name text, quantity numeric, unit_price numeric)
    LOOP
        v_total_price := v_total_price + (item.quantity * item.unit_price);
    END LOOP;

    -- Descobre a qual restaurante esta sessão pertence
    SELECT t.restaurant_id INTO v_restaurant_id
    FROM public.table_sessions ts
    JOIN public.tables t ON ts.table_id = t.id
    WHERE ts.id = p_table_session_id;

    -- Insere o pedido principal com o status 'pendente'
    INSERT INTO public.orders (restaurant_id, total, source, status, notes, waiter_id)
    VALUES (v_restaurant_id, v_total_price, 'mesa', 'pendente', p_notes, p_waiter_id)
    RETURNING id INTO v_order_id;

    -- Insere os itens do pedido
    INSERT INTO public.order_items (order_id, product_id, product_name, quantity, unit_price)
    SELECT v_order_id, (x.product_id)::bigint, x.product_name, x.quantity, x.unit_price
    FROM jsonb_to_recordset(p_items) AS x(product_id text, product_name text, quantity numeric, unit_price numeric);

    -- Cria a comanda e a vincula ao pedido
    INSERT INTO public.comandas (table_session_id, order_id, name)
    VALUES (p_table_session_id, v_order_id, p_comanda_name);

    RETURN v_order_id;
END;
$function$

