CREATE OR REPLACE FUNCTION public.create_manual_order(p_customer_phone text, p_customer_name text, p_customer_address text, p_payment_method text, p_total numeric, p_notes text, p_items order_item_data[])
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_customer_id bigint;
    v_order_id bigint;
    item public.order_item_data;
    v_restaurant_id uuid := public.get_my_restaurant_id();
BEGIN
    -- 1. Tenta encontrar o cliente pelo telefone. Se não existir, cria um novo (UPSERT).
    INSERT INTO public.customers (restaurant_id, phone, name, last_address)
    VALUES (v_restaurant_id, p_customer_phone, p_customer_name, p_customer_address)
    ON CONFLICT (restaurant_id, phone)
    DO UPDATE SET
        name = EXCLUDED.name,
        last_address = EXCLUDED.last_address
    RETURNING id INTO v_customer_id;

    -- 2. Insere o novo pedido
    INSERT INTO public.orders (restaurant_id, customer_id, source, total, payment_method, notes)
    VALUES (v_restaurant_id, v_customer_id, 'manual', p_total, p_payment_method, p_notes)
    RETURNING id INTO v_order_id;

    -- 3. Insere os itens do pedido
    FOREACH item IN ARRAY p_items
    LOOP
        INSERT INTO public.order_items (order_id, product_id, product_name, quantity, unit_price)
        VALUES (v_order_id, item.product_id, item.product_name, item.quantity, item.unit_price);
    END LOOP;

    -- 4. Retorna o ID do pedido que foi criado
    RETURN v_order_id;
END;
$function$

CREATE OR REPLACE FUNCTION public.create_restaurant_and_set_owner(restaurant_name text, contact_phone text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  new_restaurant_id UUID;
  user_id UUID := auth.uid();
  restaurant_configs JSONB;
BEGIN
  -- 1. Cria o objeto JSON de configurações
  restaurant_configs := jsonb_build_object('contact_phone', contact_phone);

  -- 2. Insere o novo restaurante com o nome e as configurações
  INSERT INTO public.restaurants (name, configs)
  VALUES (restaurant_name, restaurant_configs)
  RETURNING id INTO new_restaurant_id;

  -- 3. Atualiza a tabela de perfis do usuário com o novo ID e a role
  UPDATE public.profiles
  SET
    restaurant_id = new_restaurant_id,
    role = 'gerencial'
  WHERE id = user_id;

  -- 4. CRÍTICO: Atualiza os metadados do usuário no schema 'auth' para a RLS funcionar
  UPDATE auth.users
  SET raw_app_meta_data = raw_app_meta_data || 
    jsonb_build_object('restaurant_id', new_restaurant_id, 'role', 'gerencial')
  WHERE id = user_id;

  RETURN new_restaurant_id;
END;
$function$

CREATE OR REPLACE FUNCTION public.get_customer_and_last_order(p_restaurant_id uuid, p_customer_phone text, p_customer_name text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_customer RECORD;
    v_last_finalized_order JSONB;
    v_active_pre_order RECORD;
    v_pre_order_items JSONB;
    v_order_id_to_return BIGINT;
BEGIN
    -- Etapa 1: Encontra ou cria o cliente
    INSERT INTO public.customers (restaurant_id, phone, name)
    VALUES (p_restaurant_id, p_customer_phone, COALESCE(p_customer_name, 'Novo Cliente'))
    ON CONFLICT (restaurant_id, phone)
    DO UPDATE SET name = COALESCE(p_customer_name, customers.name)
    RETURNING * INTO v_customer;

    -- Etapa 2: Verifica se existe um 'pre-pedido' ativo para este cliente
    SELECT * INTO v_active_pre_order FROM public.orders
    WHERE customer_id = v_customer.id AND status = 'pre-pedido'
    ORDER BY created_at DESC LIMIT 1;

    -- Etapa 3: Se existir um 'pre-pedido' ativo, usa-o. Caso contrário, cria um novo.
    IF v_active_pre_order IS NOT NULL THEN
        v_order_id_to_return := v_active_pre_order.id;
    ELSE
        INSERT INTO public.orders (restaurant_id, customer_id, status, source, total)
        VALUES (p_restaurant_id, v_customer.id, 'pre-pedido', 'cardapio_digital', 0)
        RETURNING id INTO v_order_id_to_return;
    END IF;

    -- Etapa 4: Busca os itens do pré-pedido a ser retornado
    SELECT jsonb_agg(oi) INTO v_pre_order_items
    FROM public.order_items oi
    WHERE oi.order_id = v_order_id_to_return;

    -- Etapa 5: Busca o último pedido *finalizado* para a funcionalidade de ""repetir pedido""
    SELECT to_jsonb(o) || jsonb_build_object('items', (SELECT jsonb_agg(oi) FROM public.order_items oi WHERE oi.order_id = o.id))
    INTO v_last_finalized_order
    FROM public.orders o
    WHERE o.customer_id = v_customer.id AND o.status = 'finalizado'
    ORDER BY o.created_at DESC LIMIT 1;

    -- Etapa 6: Retorna todos os dados de forma estruturada
    RETURN jsonb_build_object(
        'customer', to_jsonb(v_customer),
        'lastOrder', v_last_finalized_order,
        'currentOrder', jsonb_build_object(
            'id', v_order_id_to_return,
            'items', COALESCE(v_pre_order_items, '[]'::jsonb)
        )
    );
END;
$function$

CREATE OR REPLACE FUNCTION public.get_or_create_table_session(p_table_id bigint)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_session_id bigint;
BEGIN
    -- 1. Tenta encontrar uma sessão ABERTA para a mesa especificada.
    SELECT id INTO v_session_id
    FROM public.table_sessions
    WHERE table_id = p_table_id AND status = 'open'
    LIMIT 1;

    -- 2. Se encontrou uma sessão, retorna o ID dela.
    IF v_session_id IS NOT NULL THEN
        RETURN v_session_id;
    END IF;

    -- 3. Se não encontrou, cria uma NOVA sessão e retorna o novo ID.
    INSERT INTO public.table_sessions (table_id, status)
    VALUES (p_table_id, 'open')
    RETURNING id INTO v_session_id;

    RETURN v_session_id;
END;
$function$

CREATE OR REPLACE FUNCTION public.get_public_menu_by_slug(p_restaurant_slug text)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_restaurant RECORD;
    v_categories JSON;
    v_result JSON;
    v_is_open BOOLEAN;
BEGIN
    SELECT * INTO v_restaurant
    FROM public.restaurants
    WHERE trim(regexp_replace(lower(unaccent(name)), '\s+', '-', 'g')) = p_restaurant_slug
    LIMIT 1;

    IF v_restaurant IS NULL THEN
        RETURN NULL;
    END IF;

    v_is_open := is_restaurant_open(v_restaurant.id);

    SELECT json_agg(
        json_build_object(
            'id', c.id,
            'name', c.name,
            'products', (
                SELECT json_agg(
                    json_build_object(
                        'id', p.id,
                        'name', p.name,
                        'description', p.description,
                        'price', p.price,
                        'image_url', p.image_url,
                        'half_iten', p.half_iten,
                        'popularity', p.popularity,
                        'addon_groups', (
                            SELECT json_agg(
                                json_build_object(
                                    'id', ag.id,
                                    'name', ag.name,
                                    'selection_type', ag.selection_type,
                                    'addons', (
                                        SELECT json_agg(
                                            json_build_object(
                                                'id', a.id,
                                                'name', a.name,
                                                'price', a.price
                                            ) ORDER BY a.name
                                        ) FROM public.addons a WHERE a.addon_group_id = ag.id
                                    )
                                )
                            )
                            FROM public.product_addon_groups pag
                            JOIN public.addon_groups ag ON pag.addon_group_id = ag.id
                            WHERE pag.product_id = p.id
                        )
                    ) ORDER BY p.name
                )
                FROM public.products p
                WHERE p.category_id = c.id AND p.is_available = true
            )
        )
    )
    INTO v_categories
    FROM public.categories c
    WHERE c.restaurant_id = v_restaurant.id;

    v_result := json_build_object(
        'id', v_restaurant.id,
        'name', v_restaurant.name,
        'configs', v_restaurant.configs,
        'menu', COALESCE(v_categories, '[]'::json),
        'isOpen', v_is_open
    );

    RETURN v_result;
END;
$function$

CREATE OR REPLACE FUNCTION public.get_table_details(p_table_id bigint)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_session record;
    v_comandas jsonb;
BEGIN
    -- Encontrar a sessão ativa para a mesa
    SELECT * INTO v_session FROM public.table_sessions
    WHERE table_id = p_table_id AND closed_at IS NULL AND restaurant_id = get_my_restaurant_id();

    IF v_session IS NULL THEN
        RETURN jsonb_build_object('error', 'Sessão não encontrada para esta mesa.');
    END IF;

    -- Agregar as comandas e seus respectivos pedidos
    SELECT jsonb_agg(c_data) INTO v_comandas
    FROM (
        SELECT
            c.id,
            c.name,
            c.total_amount,
            (SELECT jsonb_agg(o_data)
             FROM (
                SELECT o.id, o.status, o.total,
                (SELECT jsonb_agg(oi_data)
                    FROM (
                        SELECT oi.product_name, oi.quantity, oi.unit_price
                        FROM public.order_items oi
                        WHERE oi.order_id = o.id
                    ) AS oi_data
                ) as items
                FROM public.orders o
                WHERE o.comanda_id = c.id
             ) AS o_data
            ) as orders
        FROM public.comandas c
        WHERE c.table_session_id = v_session.id
    ) AS c_data;

    RETURN jsonb_build_object(
        'session_id', v_session.id,
        'total_amount', v_session.total_amount,
        'start_time', v_session.created_at,
        'comandas', COALESCE(v_comandas, '[]'::jsonb)
    );
END;
$function$

CREATE OR REPLACE FUNCTION public.handle_ingredient_stock_change()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- Se a quantidade em estoque mudou, chama a função de verificação
    IF NEW.stock_quantity <> OLD.stock_quantity THEN
        PERFORM public.update_availability_for_products_using_ingredient(NEW.id);
    END IF;
    RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.open_table_session(p_table_id bigint, p_comanda_name text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_restaurant_id uuid := get_my_restaurant_id();
    v_session_id uuid;
    v_comanda_id uuid;
BEGIN
    -- Cria a sessão da mesa
    INSERT INTO public.table_sessions (restaurant_id, table_id)
    VALUES (v_restaurant_id, p_table_id)
    RETURNING id INTO v_session_id;

    -- Cria a primeira comanda para a sessão
    INSERT INTO public.comandas (table_session_id, name)
    VALUES (v_session_id, p_comanda_name)
    RETURNING id INTO v_comanda_id;

    RETURN jsonb_build_object('session_id', v_session_id, 'comanda_id', v_comanda_id);
END;
$function$

CREATE OR REPLACE FUNCTION public.update_order(p_order_id bigint, p_new_address text, p_new_payment_method text, p_new_total numeric, p_new_items order_item_data[])
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_customer_id bigint;
    item public.order_item_data;
BEGIN
    -- 1. Descobrir qual é o ID do cliente associado a este pedido
    SELECT customer_id INTO v_customer_id FROM public.orders WHERE id = p_order_id;

    -- 2. Atualizar o endereço na tabela de clientes
    IF v_customer_id IS NOT NULL THEN
        UPDATE public.customers
        SET last_address = p_new_address
        WHERE id = v_customer_id;
    END IF;

    -- 3. Atualizar o pedido principal com o novo total e forma de pagamento
    UPDATE public.orders
    SET
        total = p_new_total,
        payment_method = p_new_payment_method
    WHERE id = p_order_id;

    -- 4. Deletar TODOS os itens antigos deste pedido para evitar duplicatas
    DELETE FROM public.order_items WHERE order_id = p_order_id;

    -- 5. Inserir os novos itens do pedido
    FOREACH item IN ARRAY p_new_items
    LOOP
        INSERT INTO public.order_items (order_id, product_id, product_name, quantity, unit_price)
        VALUES (p_order_id, item.product_id, item.product_name, item.quantity, item.unit_price);
    END LOOP;
END;
$function$

CREATE OR REPLACE FUNCTION public.update_product_availability_from_stock()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- Apenas desativa se o controle for por PRODUTO e o estoque for <= 0
    IF NEW.stock_control_enabled = TRUE AND NEW.stock_control_type = 'product' AND NEW.stock_quantity <= 0 THEN
        NEW.is_available := FALSE;
    END IF;
    RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.validate_coupon(p_code text, p_customer_id bigint)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_coupon RECORD;
    v_has_previous_orders BOOLEAN;
BEGIN
    -- 1. Busca o cupom pelo código e restaurante do cliente
    SELECT * INTO v_coupon
    FROM public.promotions
    WHERE coupon_code = upper(trim(p_code))
      AND restaurant_id = (SELECT restaurant_id FROM public.customers WHERE id = p_customer_id LIMIT 1);

    -- 2. Verifica se o cupom existe
    IF v_coupon IS NULL THEN
        RETURN jsonb_build_object('valid', false, 'message', 'Cupom inválido ou não encontrado.');
    END IF;

    -- 3. Verifica se está ativo
    IF NOT v_coupon.is_active THEN
        RETURN jsonb_build_object('valid', false, 'message', 'Este cupom não está mais ativo.');
    END IF;

    -- 4. Verifica o limite de usos
    IF v_coupon.max_uses IS NOT NULL AND v_coupon.uses_count >= v_coupon.max_uses THEN
        RETURN jsonb_build_object('valid', false, 'message', 'Este cupom atingiu o limite de usos.');
    END IF;

    -- 5. Verifica se é um cupom de "primeiro pedido"
    IF v_coupon.coupon_type = 'primeiro_pedido' THEN
        SELECT EXISTS (
            SELECT 1
            FROM public.orders
            WHERE customer_id = p_customer_id
              AND status <> 'pre-pedido'
        ) INTO v_has_previous_orders;

        IF v_has_previous_orders THEN
            RETURN jsonb_build_object('valid', false, 'message', 'Este cupom é válido apenas para o primeiro pedido.');
        END IF;
    END IF;

    -- 6. Se todas as validações passaram
    RETURN jsonb_build_object('valid', true, 'message', 'Cupom aplicado!', 'coupon', row_to_json(v_coupon));
END;
$function$
